import React, { useState, useEffect } from "react";
import axios from "axios";

const Dashboard = () => {
  const [productos, setProductos] = useState([]);
  const [formData, setFormData] = useState({
    productoID: null,
    nombre: "",
    descripcion: "",
    precio: "",
    stock: "",
  });
  const [modoEditar, setModoEditar] = useState(false);

  // Cargar productos al inicio
  useEffect(() => {
    obtenerProductos();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (modoEditar) {
        await axios.put(
          `http://localhost:5000/api/productos/${formData.productoID}`,
          formData
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", formData);
      }

      setFormData({
        productoID: null,
        nombre: "",
        descripcion: "",
        precio: "",
        stock: "",
      });
      setModoEditar(false);
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  const editarProducto = (producto) => {
    setFormData(producto);
    setModoEditar(true);
  };

  const eliminarProducto = async (productoID) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${productoID}`);
        obtenerProductos();
      } catch (error) {
        console.error("Error al eliminar producto:", error);
      }
    }
  };

  return (
    <div className="container py-4">
      <h2 className="text-center mb-4">Panel de Productos</h2>

      {/* Formulario */}
      <div className="card shadow-sm p-3 mb-4">
        <h5>{modoEditar ? "Editar Producto" : "Agregar Producto"}</h5>
        <form onSubmit={handleSubmit}>
          <div className="row g-3">
            <div className="col-md-3">
              <input
                type="text"
                name="nombre"
                className="form-control"
                placeholder="Nombre"
                value={formData.nombre}
                onChange={handleChange}
                required
              />
            </div>
            <div className="col-md-3">
              <input
                type="text"
                name="descripcion"
                className="form-control"
                placeholder="Descripción"
                value={formData.descripcion}
                onChange={handleChange}
              />
            </div>
            <div className="col-md-2">
              <input
                type="number"
                name="precio"
                className="form-control"
                placeholder="Precio"
                value={formData.precio}
                onChange={handleChange}
                required
              />
            </div>
            <div className="col-md-2">
              <input
                type="number"
                name="stock"
                className="form-control"
                placeholder="Stock"
                value={formData.stock}
                onChange={handleChange}
                required
              />
            </div>
            <div className="col-md-2 d-grid">
              <button type="submit" className="btn btn-success">
                {modoEditar ? "Actualizar" : "Agregar"}
              </button>
            </div>
          </div>
        </form>
      </div>

      {/* Tabla */}
      <div className="card shadow-sm p-3">
        <table className="table table-striped">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Nombre</th>
              <th>Descripción</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productos.map((p) => (
              <tr key={p.productoID}>
                <td>{p.productoID}</td>
                <td>{p.nombre}</td>
                <td>{p.descripcion}</td>
                <td>${p.precio}</td>
                <td>{p.stock}</td>
                <td>
                  <button
                    onClick={() => editarProducto(p)}
                    className="btn btn-warning btn-sm me-2"
                  >
                    Editar
                  </button>
                  <button
                    onClick={() => eliminarProducto(p.productoID)}
                    className="btn btn-danger btn-sm"
                  >
                    Eliminar
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Dashboard;
